/* Lightweight stub for html5-qrcode to avoid missing static errors in local env.
   Replace with official library for production scanner UX. */
window.Html5Qrcode = window.Html5Qrcode || function(){
  this.start = async function(){ return Promise.resolve(); };
  this.stop = async function(){ return Promise.resolve(); };
  this.clear = async function(){ return Promise.resolve(); };
};
window.Html5QrcodeScanner = window.Html5QrcodeScanner || function(){
  this.render = function(){};
  this.clear = async function(){ return Promise.resolve(); };
};
